import { cn } from '@/utils/cn';
import { getColor } from '@/utils/helper';
import { cva, type VariantProps } from 'class-variance-authority';
import RefreshCw from 'lucide-solid/icons/refresh-cw';
import {
  Accessor,
  Component,
  createEffect,
  createMemo,
  createSignal,
  createUniqueId,
  For,
  JSXElement,
  mergeProps,
  on,
  onCleanup,
  onMount,
  Setter,
  Show,
} from 'solid-js';
import { Button } from '../button';
import type { FolderItem, ItemClickInfo, MenuErrorInfo, MenuItem, MenuProps } from './menu.types';

const menuVariants = cva('menu', {
  variants: {
    size: { xs: 'menu-xs', sm: 'menu-sm', md: 'menu-md', lg: 'menu-lg', xl: 'menu-xl' },
    direction: { vertical: 'menu-vertical', horizontal: 'menu-horizontal' },
  },
});

export type MenuVariantsProps = VariantProps<typeof menuVariants>;

class NodeRegistry {
  private parentMap = new Map<string, string | null>();
  register(id: string, parentId: string | null) {
    this.parentMap.set(id, parentId);
  }
  getPath(id: string): string[] {
    const path: string[] = [];
    let currentId: string | null | undefined = id;
    while (currentId != null) {
      path.unshift(currentId);
      currentId = this.parentMap.get(currentId);
    }
    return path;
  }
  has(id: string): boolean {
    return this.parentMap.has(id);
  }
  clear() {
    this.parentMap.clear();
  }
}

class LazyFolderRegistry {
  private refreshFns = new Map<string, () => void>();
  register(id: string, refreshFn: () => void) {
    this.refreshFns.set(id, refreshFn);
  }
  unregister(id: string) {
    this.refreshFns.delete(id);
  }
  refresh(id: string) {
    const fn = this.refreshFns.get(id);
    if (fn) fn();
  }
  refreshAll() {
    this.refreshFns.forEach(fn => fn());
  }
  has(id: string): boolean {
    return this.refreshFns.has(id);
  }
  clear() {
    this.refreshFns.clear();
  }
}

const LazyFolderContent: Component<{
  item: FolderItem;
  renderItems: (item: MenuItem, parentId: string | null) => JSXElement;
  parentId: string | null;
  shouldLoad: Accessor<boolean>;
  isLoading: Accessor<boolean>;
  setIsLoading: Setter<boolean>;
  onLoadError: (error: unknown) => void;
  onRegisterRefresh: (refreshFn: () => void) => void;
}> = props => {
  const [loadedItems, setLoadedItems] = createSignal<MenuItem[] | null>(null);
  const loadItems = async (force = false) => {
    if (props.isLoading()) return;
    if (loadedItems() !== null && !force) return;
    if (!props.item.lazyItems) return;
    props.setIsLoading(true);
    try {
      const items = await props.item.lazyItems();
      setLoadedItems(items);
    } catch (e) {
      props.onLoadError(e);
    } finally {
      props.setIsLoading(false);
    }
  };
  const refresh = () => {
    loadItems(true);
  };
  onMount(() => {
    props.onRegisterRefresh(refresh);
  });
  createEffect(
    on(
      () => props.shouldLoad(),
      shouldLoad => {
        if (shouldLoad && loadedItems() === null) {
          loadItems();
        }
      },
      { defer: true },
    ),
  );
  return (
    <Show when={loadedItems()}>
      <For each={loadedItems()!}>{subItem => props.renderItems(subItem, props.parentId)}</For>
    </Show>
  );
};

const ACTIVE_CLASSNAME = '_6ca32a';
export const Menu: Component<MenuProps> = p => {
  p = mergeProps(
    { size: 'md', direction: 'vertical', color: 'secondary', highlightActive: true } as const,
    p,
  );
  let ulRootRef: HTMLUListElement;
  const nodeRegistry = new NodeRegistry();
  const lazyFolderRegistry = new LazyFolderRegistry();
  function addActiveClassForId(id: string) {
    if (!ulRootRef || !p.highlightActive) return;
    const path = nodeRegistry.getPath(id);
    if (path.length === 0) return;

    const elements = Array.from(ulRootRef.getElementsByClassName(ACTIVE_CLASSNAME));

    for (const el of elements) el.classList.remove(ACTIVE_CLASSNAME);
    for (const nodeId of path) document.getElementById(nodeId)?.classList?.add(ACTIVE_CLASSNAME);
  }
  function expandPathToId(id: string) {
    const path = nodeRegistry.getPath(id);
    for (const nodeId of path) {
      const element = document.getElementById(nodeId);
      if (!element) continue;
      const details = element.querySelector(':scope > details') as HTMLDetailsElement | null;
      if (details && !details.open) {
        details.open = true;
      }
    }
  }
  function focusById(id: string) {
    if (!nodeRegistry.has(id)) {
      console.warn(`Menu.focusById: Node with id "${id}" not found in registry`);
      return;
    }
    expandPathToId(id);
    addActiveClassForId(id);
  }
  function collapseById(id: string) {
    const element = document.getElementById(id);
    if (!element) {
      console.warn(`Menu.collapseById: Element with id "${id}" not found`);
      return;
    }
    const details = element.querySelector(':scope > details') as HTMLDetailsElement | null;
    if (details) {
      details.open = false;
      const elements = details.getElementsByClassName(ACTIVE_CLASSNAME);
      for (const el of elements) el.classList.remove(ACTIVE_CLASSNAME);
      element.classList.remove(ACTIVE_CLASSNAME);
    }
  }
  function refreshById(id: string) {
    if (!lazyFolderRegistry.has(id)) {
      console.warn(`Menu.refreshById: Lazy folder with id "${id}" not found`);
      return;
    }
    lazyFolderRegistry.refresh(id);
  }
  function refreshAll() {
    lazyFolderRegistry.refreshAll();
  }
  function collapseAll() {
    if (!ulRootRef) return;
    const detailsList = ulRootRef.querySelectorAll('details');
    detailsList.forEach(d => (d.open = false));
  }
  function expandedAll() {
    if (!ulRootRef) return;
    const detailsList = ulRootRef.querySelectorAll('details');
    detailsList.forEach(d => (d.open = true));
  }
  function collapseOtherRootFolders(exceptId: string) {
    if (!ulRootRef) return;
    // Only collapse direct children (level 1 folders)
    const rootFolders = ulRootRef.querySelectorAll(':scope > li.folder > details');
    rootFolders.forEach(details => {
      const li = details.parentElement;
      if (li && li.id !== exceptId && (details as HTMLDetailsElement).open) {
        (details as HTMLDetailsElement).open = false;
      }
    });
  }
  function renderItems(item: MenuItem, parentId: string | null = null) {
    const itemId = item.id ?? createUniqueId();
    nodeRegistry.register(itemId, parentId);

    if (item.type === 'folder') {
      const folderItem = mergeProps(
        { defaultExpanded: item.defaultExpanded ?? p.defaultExpanded ?? false },
        item,
        { id: itemId },
      );
      const isLazyFolder = folderItem.lazyItems !== undefined;
      const [shouldLoad, setShouldLoad] = createSignal(folderItem.defaultExpanded);
      const [isLoading, setIsLoading] = createSignal(false);
      let detailsRef: HTMLDetailsElement | undefined;

      const handleToggle = (e: Event) => {
        const details = e.currentTarget as HTMLDetailsElement;
        const isExpanded = details.open;
        if (isLoading()) {
          e.preventDefault();
          return;
        }
        if (isLazyFolder) {
          setShouldLoad(isExpanded);
        }
      };

      const handleLoadError = (error: unknown) => {
        if (detailsRef) {
          detailsRef.open = false;
        }
        setShouldLoad(false);
        if (p.onError) {
          const errorInfo: MenuErrorInfo = {
            source: 'folder',
            itemId,
            path: nodeRegistry.getPath(itemId),
            error,
            message: error instanceof Error ? error.message : 'Failed to load folder items',
          };
          p.onError(errorInfo);
        }
      };

      const handleFolderClick = (e: MouseEvent) => {
        e.stopPropagation();
        if (isLoading() || item.disabled) {
          e.preventDefault();
          return;
        }

        const currentIsExpanded = detailsRef?.open ?? folderItem.defaultExpanded;
        const willExpand = !currentIsExpanded;

        // In horizontal mode, collapse other root folders when expanding a root folder
        if (p.direction === 'horizontal' && parentId === null && willExpand) {
          collapseOtherRootFolders(itemId);
        }

        if (detailsRef?.open === false) {
          addActiveClassForId(itemId);
        } else {
          setTimeout(() => {
            collapseById(itemId);
          });
        }

        if (p.onItemClick) {
          const isExpanded = willExpand;
          const info: ItemClickInfo = {
            id: itemId,
            path: nodeRegistry.getPath(itemId),
            type: 'folder',
            isExpanded,
            data: item.data,
          };
          p.onItemClick(info);
        }
      };
      return (
        <li
          class={cn(
            'folder',
            (folderItem.disabled || isLoading()) && 'menu-disabled',
            p.class?.itemWrap,
          )}
          id={itemId}
        >
          <details ref={detailsRef} open={folderItem.defaultExpanded} onToggle={handleToggle}>
            <summary
              class={cn(isLoading() && 'after:hidden', p.class?.itemHeader)}
              onClick={handleFolderClick}
            >
              {folderItem.content as Element}
              <Show when={isLoading()}>
                <span class="loading loading-spinner loading-xs"></span>
              </Show>
            </summary>
            <ul>
              <Show
                when={isLazyFolder}
                fallback={
                  <For each={(folderItem as { items: MenuItem[] }).items}>
                    {subItem => renderItems(subItem, itemId)}
                  </For>
                }
              >
                <LazyFolderContent
                  {...{
                    renderItems,
                    shouldLoad,
                    isLoading,
                    setIsLoading,
                    item: folderItem,
                    parentId: itemId,
                    onLoadError: handleLoadError,
                    onRegisterRefresh: refreshFn => lazyFolderRegistry.register(itemId, refreshFn),
                  }}
                />
              </Show>
            </ul>
          </details>
        </li>
      );
    }
    if (item.type === 'file') {
      const handleFileClick = (e: MouseEvent) => {
        e.stopPropagation();
        addActiveClassForId(itemId);

        if (p.onItemClick) {
          const info: ItemClickInfo = {
            id: itemId,
            path: nodeRegistry.getPath(itemId),
            type: 'file',
            ...(item.data && { data: item.data }),
          };
          p.onItemClick(info);
        }
      };
      return (
        <li
          class={cn('file', item.disabled && 'menu-disabled', p.class?.itemWrap)}
          id={itemId}
          tabindex="0"
          onClick={handleFileClick}
        >
          <div>{item.content as Element}</div>
        </li>
      );
    }
    if (item.type === 'title') {
      const handleTitleClick = (e: MouseEvent) => {
        e.stopPropagation();

        const li = document.getElementById(itemId);
        if (li && li.classList.contains(ACTIVE_CLASSNAME)) {
          const elements = li.getElementsByClassName(ACTIVE_CLASSNAME);
          for (const el of elements) el.classList.remove(ACTIVE_CLASSNAME);
          li.classList.remove(ACTIVE_CLASSNAME);
        } else {
          addActiveClassForId(itemId);
        }

        if (p.onItemClick) {
          const info: ItemClickInfo = {
            id: itemId,
            path: nodeRegistry.getPath(itemId),
            type: 'title',
            ...(item.data && { data: item.data }),
          };
          p.onItemClick(info);
        }
      };
      return (
        <li class={cn('title', item.disabled && 'menu-disabled', p.class?.itemWrap)} id={itemId}>
          <h4 class="menu-title" onClick={handleTitleClick}>
            {item.content as Element}
          </h4>
          <ul>
            <For each={item.items}>{subItem => renderItems(subItem, itemId)}</For>
          </ul>
        </li>
      );
    }
  }
  const isLazyRoot = p.lazyItems !== undefined;
  const [rootItems, setRootItems] = createSignal<MenuItem[] | null>(
    isLazyRoot ? null : (p.items ?? []),
  );
  const [isRootLoading, setIsRootLoading] = createSignal(false);

  createEffect(
    on(
      () => p.items,
      items => {
        if (!isLazyRoot && items) {
          nodeRegistry.clear();
          lazyFolderRegistry.clear();
          setRootItems(items);
        }
      },
      { defer: true },
    ),
  );

  onCleanup(function clearMenuRegistries() {
    nodeRegistry.clear();
    lazyFolderRegistry.clear();
  });

  const loadRootItems = async () => {
    if (!p.lazyItems || rootItems() !== null || isRootLoading()) return;
    setIsRootLoading(true);
    try {
      const items = await p.lazyItems();
      setRootItems(items);
    } catch (e) {
      if (p.onError) {
        const errorInfo: MenuErrorInfo = {
          source: 'root',
          error: e,
          message: e instanceof Error ? e.message : 'Failed to load menu items',
        };
        p.onError(errorInfo);
      }
    } finally {
      setIsRootLoading(false);
    }
  };
  if (isLazyRoot) {
    loadRootItems();
  }
  const menuClass = createMemo(() =>
    cn(menuVariants({ size: p.size, direction: p.direction }), getColor(p.color), p.class?.root),
  );

  if (p.setMenuFunction) {
    p.setMenuFunction({
      focusById,
      collapseById,
      refreshById,
      refreshAll,
      collapseAll,
      expandedAll,
    });
  }
  return (
    <>
      <Show when={isRootLoading()}>
        <div class={cn(menuClass(), 'flex size-full justify-center p-4')}>
          <span class="loading loading-spinner loading-md m-auto"></span>
        </div>
      </Show>
      <Show when={!isRootLoading()}>
        <Show
          when={rootItems() && rootItems()!.length > 0}
          fallback={
            <div class="text-base-content/50 flex flex-col items-center justify-center gap-2 p-4 text-center text-sm italic">
              <span>No menu items available.</span>
              <Button
                icon={<RefreshCw size={10} />}
                variant={'default'}
                size={'4xs'}
                class="w-fit px-1.5"
                onClick={loadRootItems}
              >
                Try again
              </Button>
            </div>
          }
        >
          <ul class={menuClass()} ref={ele => (ulRootRef = ele)} {...(p.id && { id: p.id })}>
            <For each={rootItems()!}>{item => renderItems(item)}</For>
          </ul>
        </Show>
      </Show>
    </>
  );
};
